+  /** Flush accumulated PTY data to the WebSocket */
+  const flushBatch = () => {
+    batchTimer = null;
+    if (!batchBuffer || ws.readyState !== WebSocket.OPEN) {
+      batchBuffer = '';
+      batchDataEvents = 0;
+      return;
+    }
+    batchFlushCount++;
+    const coalesced = batchDataEvents;
+    const bytes = batchBuffer.length;
+    if (coalesced > 1) {
